// jamaah_document_messages.go — hand-written proto message types for the
// UploadDocument and ReviewDocument RPCs added in S3-E-02 (F3-W1 scaffold).
//
// NOTE: These types would normally be generated by protoc from jamaah.proto.
// They are written by hand because protoc is not available in the sandbox.
// Run `make genpb` to regenerate cleanly from jamaah.proto once protoc is
// available in the build environment.
//
// UploadDocument — stores document metadata and initiates the verification queue.
// ReviewDocument — approve or reject a document (ops staff action).

package pb

// UploadDocumentRequest carries the document metadata for a new upload.
type UploadDocumentRequest struct {
	JamaahId   string
	BookingId  string
	DocType    string // ktp | passport | photo | other
	FilePath   string // GCS path: jamaah/{jamaah_id}/{doc_type}/{doc_id}
	UploadedBy string // staff user ID if uploaded on behalf; empty for self-upload
}

func (x *UploadDocumentRequest) GetJamaahId() string {
	if x == nil {
		return ""
	}
	return x.JamaahId
}
func (x *UploadDocumentRequest) GetBookingId() string {
	if x == nil {
		return ""
	}
	return x.BookingId
}
func (x *UploadDocumentRequest) GetDocType() string {
	if x == nil {
		return ""
	}
	return x.DocType
}
func (x *UploadDocumentRequest) GetFilePath() string {
	if x == nil {
		return ""
	}
	return x.FilePath
}
func (x *UploadDocumentRequest) GetUploadedBy() string {
	if x == nil {
		return ""
	}
	return x.UploadedBy
}

// UploadDocumentResponse returns the created document record.
type UploadDocumentResponse struct {
	DocumentId string
	Status     string // pending | approved | rejected
}

func (x *UploadDocumentResponse) GetDocumentId() string {
	if x == nil {
		return ""
	}
	return x.DocumentId
}
func (x *UploadDocumentResponse) GetStatus() string {
	if x == nil {
		return ""
	}
	return x.Status
}

// ReviewDocumentRequest carries the review action from ops staff.
type ReviewDocumentRequest struct {
	DocumentId      string
	Action          string // approve | reject
	RejectionReason string // required when action = reject
	ReviewedBy      string // staff user ID
}

func (x *ReviewDocumentRequest) GetDocumentId() string {
	if x == nil {
		return ""
	}
	return x.DocumentId
}
func (x *ReviewDocumentRequest) GetAction() string {
	if x == nil {
		return ""
	}
	return x.Action
}
func (x *ReviewDocumentRequest) GetRejectionReason() string {
	if x == nil {
		return ""
	}
	return x.RejectionReason
}
func (x *ReviewDocumentRequest) GetReviewedBy() string {
	if x == nil {
		return ""
	}
	return x.ReviewedBy
}

// ReviewDocumentResponse returns the updated document record.
type ReviewDocumentResponse struct {
	DocumentId string
	Status     string // approved | rejected
}

func (x *ReviewDocumentResponse) GetDocumentId() string {
	if x == nil {
		return ""
	}
	return x.DocumentId
}
func (x *ReviewDocumentResponse) GetStatus() string {
	if x == nil {
		return ""
	}
	return x.Status
}
